import InfoCard from "../../components/general/infoCard"

const ContactCards = ({ className, address, phoneNumber, email, faxNumber, googleMapsLink }) => (
    <div className={`${className} space-y-4 w-full`}>
        {/*  border-4 border-orange-200 */}

        <InfoCard
            title="Address"
            info={address.trim()}
            href={googleMapsLink}
            linkClass="whitespace-pre-wrap"
            newTab={true}
        />

        <InfoCard
            title="Phone Number"
            info={phoneNumber}
            href={`tel:${phoneNumber}`}
        />

        <InfoCard
            title="Email"
            info={email}
            href={`mailto:${email}`}
        />

        <InfoCard title="Fax">
            {faxNumber}
        </InfoCard>

    </div>
)

export default ContactCards

